const PROCESSING_FEE = 5;

type Item = { type: string };
type QuoteStep = { op: "quote"; items: Item[] };
type Scenario = { customer: { yearsWithMHPCO: number }; steps: QuoteStep[] };

export const runScenario = (input: Scenario): { results: { premium: number }[] } => {
  const results = input.steps.map((step) => {
    const itemsBase = step.items.reduce(
      (sum, item) => sum + (item.type === "sword" ? 100 : 0),
      0,
    );
    return { premium: itemsBase + PROCESSING_FEE };
  });
  return { results };
};

